{
  "name": "Labor Case Management System",
  "description": "A comprehensive tool for the Assistant Commissioner of Labour to track complaints, manage joint meeting schedules, and generate official government notices."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum CaseStatus {
  OPEN = 'Open',
  CLOSED = 'Closed',
  PENDING = 'Pending'
}

export interface Hearing {
  id: string;
  date: string;
  remarks: string;
  isCompleted: boolean;
}

export interface LaborCase {
  id: string;
  fileNumber: string; // Format: A/0000/202X
  receivedDate: string;
  section: string;

  applicantName: string;
  applicantPhones: string[];
  applicantAddress: string;

  managementName: string;
  managementPerson: string;
  managementPhone: string;
  managementAddress: string;

  subject: string;
  amountRecovered: number;
  status: CaseStatus;

  hearings: Hearing[];
  createdAt: string;
}

export type ViewType = 'dashboard' | 'create' | 'details' | 'notice' | 'settings';

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  PlusCircle, 
  Users, 
  Settings, 
  FileText, 
  Search,
  Bell,
  LogOut,
  Menu,
  X,
  ChevronRight
} from 'lucide-react';
import { LaborCase, ViewType, CaseStatus } from './types';
import Dashboard from './components/Dashboard';
import CaseForm from './components/CaseForm';
import CaseDetails from './components/CaseDetails';
import NoticePreview from './components/NoticePreview';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [selectedCaseId, setSelectedCaseId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [cases, setCases] = useState<LaborCase[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  // Initial mock data
  useEffect(() => {
    const savedCases = localStorage.getItem('labor_cases');
    if (savedCases) {
      setCases(JSON.parse(savedCases));
    } else {
      const mockCases: LaborCase[] = [
        {
          id: '1',
          fileNumber: 'A/1024/2024',
          receivedDate: '2024-02-15',
          section: 'Wages',
          applicantName: 'M. Ramesh',
          applicantPhones: ['9876543210'],
          applicantAddress: 'Plot 45, Jubilee Hills, Hyderabad',
          managementName: 'Innova Tech Solutions',
          managementPerson: 'Sanjay Kumar',
          managementPhone: '8887776660',
          managementAddress: 'HITEC City, Phase 2, Hyderabad',
          subject: 'Non-payment of overtime wages for 6 months',
          amountRecovered: 45000,
          status: CaseStatus.OPEN,
          hearings: [
            { id: 'h1', date: '2024-03-01', remarks: 'Preliminary hearing scheduled', isCompleted: true }
          ],
          createdAt: new Date().toISOString()
        }
      ];
      setCases(mockCases);
      localStorage.setItem('labor_cases', JSON.stringify(mockCases));
    }
  }, []);

  const saveCases = (updatedCases: LaborCase[]) => {
    setCases(updatedCases);
    localStorage.setItem('labor_cases', JSON.stringify(updatedCases));
  };

  const handleCreateCase = (newCase: LaborCase) => {
    saveCases([newCase, ...cases]);
    setActiveView('dashboard');
  };

  const handleUpdateCase = (updatedCase: LaborCase) => {
    saveCases(cases.map(c => c.id === updatedCase.id ? updatedCase : c));
  };

  const filteredCases = useMemo(() => {
    return cases.filter(c => 
      c.fileNumber.toLowerCase().includes(searchQuery.toLowerCase()) ||
      c.applicantName.toLowerCase().includes(searchQuery.toLowerCase()) ||
      c.managementName.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [cases, searchQuery]);

  const selectedCase = useMemo(() => {
    return cases.find(c => c.id === selectedCaseId) || null;
  }, [cases, selectedCaseId]);

  const renderView = () => {
    switch (activeView) {
      case 'dashboard':
        return (
          <Dashboard 
            cases={filteredCases} 
            onViewDetails={(id) => {
              setSelectedCaseId(id);
              setActiveView('details');
            }}
            onGenerateNotice={(id) => {
              setSelectedCaseId(id);
              setActiveView('notice');
            }}
          />
        );
      case 'create':
        return <CaseForm onSubmit={handleCreateCase} onCancel={() => setActiveView('dashboard')} />;
      case 'details':
        return selectedCase ? (
          <CaseDetails 
            caseItem={selectedCase} 
            onUpdate={handleUpdateCase} 
            onBack={() => setActiveView('dashboard')} 
            onNotice={() => setActiveView('notice')}
          />
        ) : null;
      case 'notice':
        return selectedCase ? (
          <NoticePreview 
            caseItem={selectedCase} 
            onBack={() => setActiveView('details')} 
          />
        ) : null;
      default:
        return <div className="p-8 text-center text-gray-500">View under construction</div>;
    }
  };

  return (
    <div className="min-h-screen flex">
      {/* Sidebar */}
      <aside className={`
        ${isSidebarOpen ? 'w-64' : 'w-20'} 
        bg-slate-900 text-white transition-all duration-300 flex flex-col no-print
      `}>
        <div className="p-6 flex items-center gap-3 border-b border-slate-800">
          <div className="w-8 h-8 bg-blue-500 rounded flex items-center justify-center font-bold text-lg">L</div>
          {isSidebarOpen && <span className="font-bold text-sm tracking-tight leading-tight">LABOR COMMISSIONER <br/><span className="text-blue-400">RANGAREDDY</span></span>}
        </div>

        <nav className="flex-1 mt-6 px-4 space-y-2">
          <button 
            onClick={() => setActiveView('dashboard')}
            className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg transition-colors ${activeView === 'dashboard' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <LayoutDashboard size={20} />
            {isSidebarOpen && <span>Dashboard</span>}
          </button>
          <button 
            onClick={() => setActiveView('create')}
            className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg transition-colors ${activeView === 'create' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <PlusCircle size={20} />
            {isSidebarOpen && <span>Create Case</span>}
          </button>
          <button 
            className="w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-slate-400 hover:bg-slate-800 hover:text-white"
          >
            <Users size={20} />
            {isSidebarOpen && <span>Staff Management</span>}
          </button>
          <button 
            className="w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-slate-400 hover:bg-slate-800 hover:text-white"
          >
            <Settings size={20} />
            {isSidebarOpen && <span>Settings</span>}
          </button>
        </nav>

        <div className="p-4 border-t border-slate-800">
          <button className="w-full flex items-center gap-3 px-3 py-2 rounded-lg text-slate-400 hover:bg-slate-800 hover:text-white">
            <LogOut size={20} />
            {isSidebarOpen && <span>Logout</span>}
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <header className="h-16 bg-white border-b border-gray-200 flex items-center justify-between px-6 no-print">
          <div className="flex items-center gap-4 flex-1">
            <button 
              onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              className="p-1 hover:bg-gray-100 rounded md:hidden"
            >
              <Menu size={24} />
            </button>
            <div className="relative max-w-md w-full">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input 
                type="text" 
                placeholder="Search File No, Applicant, Management..."
                className="w-full pl-10 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white text-sm"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          </div>

          <div className="flex items-center gap-4">
            <button className="relative p-2 text-gray-500 hover:bg-gray-100 rounded-full">
              <Bell size={20} />
              <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
            </button>
            <div className="flex items-center gap-3 pl-4 border-l border-gray-200">
              <div className="text-right hidden sm:block">
                <p className="text-sm font-semibold text-gray-900">Asst. Commissioner</p>
                <p className="text-xs text-gray-500">Labour Department</p>
              </div>
              <img src="https://picsum.photos/seed/admin/40" alt="Admin" className="w-9 h-9 rounded-full bg-gray-200" />
            </div>
          </div>
        </header>

        {/* View Port */}
        <div className="flex-1 overflow-y-auto p-4 md:p-8">
          {renderView()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { LaborCase, CaseStatus, Hearing } from '../types';
import { 
  ArrowLeft, 
  Calendar, 
  Clock, 
  MapPin, 
  User, 
  Building, 
  Plus, 
  CheckCircle2, 
  Edit3, 
  FileText,
  DollarSign
} from 'lucide-react';

interface CaseDetailsProps {
  caseItem: LaborCase;
  onUpdate: (updatedCase: LaborCase) => void;
  onBack: () => void;
  onNotice: () => void;
}

const CaseDetails: React.FC<CaseDetailsProps> = ({ caseItem, onUpdate, onBack, onNotice }) => {
  const [isAddingHearing, setIsAddingHearing] = useState(false);
  const [newHearing, setNewHearing] = useState({ date: '', remarks: '' });
  const [isEditingAmount, setIsEditingAmount] = useState(false);
  const [recoveryAmount, setRecoveryAmount] = useState(caseItem.amountRecovered.toString());

  const handleAddHearing = () => {
    if (!newHearing.date) return;
    const hearing: Hearing = {
      id: Date.now().toString(),
      date: newHearing.date,
      remarks: newHearing.remarks,
      isCompleted: false
    };
    onUpdate({
      ...caseItem,
      hearings: [...caseItem.hearings, hearing]
    });
    setIsAddingHearing(false);
    setNewHearing({ date: '', remarks: '' });
  };

  const toggleStatus = () => {
    onUpdate({
      ...caseItem,
      status: caseItem.status === CaseStatus.OPEN ? CaseStatus.CLOSED : CaseStatus.OPEN
    });
  };

  const saveAmount = () => {
    onUpdate({
      ...caseItem,
      amountRecovered: parseFloat(recoveryAmount)
    });
    setIsEditingAmount(false);
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-4">
          <button 
            onClick={onBack}
            className="p-2 hover:bg-gray-200 rounded-full transition-colors"
          >
            <ArrowLeft size={20} />
          </button>
          <div>
            <div className="flex items-center gap-3">
              <h1 className="text-2xl font-bold text-gray-900">{caseItem.fileNumber}</h1>
              <span className={`px-2.5 py-0.5 rounded-full text-xs font-semibold ${
                caseItem.status === CaseStatus.OPEN ? 'bg-orange-100 text-orange-700' : 'bg-emerald-100 text-emerald-700'
              }`}>
                {caseItem.status}
              </span>
            </div>
            <p className="text-gray-500 text-sm">Registered on {caseItem.receivedDate} • Section: {caseItem.section}</p>
          </div>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={onNotice}
            className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-300 rounded-lg text-sm font-medium hover:bg-gray-50 shadow-sm"
          >
            <FileText size={18} />
            Generate Notice
          </button>
          <button 
            onClick={toggleStatus}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium shadow-sm transition-colors ${
              caseItem.status === CaseStatus.OPEN 
                ? 'bg-emerald-600 text-white hover:bg-emerald-700' 
                : 'bg-orange-600 text-white hover:bg-orange-700'
            }`}
          >
            <CheckCircle2 size={18} />
            Mark as {caseItem.status === CaseStatus.OPEN ? 'Closed' : 'Open'}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column: Case Information */}
        <div className="lg:col-span-2 space-y-6">
          {/* Subject & Amount */}
          <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-gray-100 flex justify-between items-start">
              <div className="space-y-1">
                <h2 className="text-sm font-semibold text-gray-500 uppercase tracking-wider">Subject of Representation</h2>
                <p className="text-gray-900 font-medium leading-relaxed">{caseItem.subject}</p>
              </div>
              <div className="bg-blue-50 p-4 rounded-xl border border-blue-100 min-w-[180px]">
                <div className="flex items-center justify-between mb-1">
                  <span className="text-xs font-bold text-blue-600 uppercase">Recovery</span>
                  {!isEditingAmount && (
                    <button onClick={() => setIsEditingAmount(true)} className="text-blue-400 hover:text-blue-600">
                      <Edit3 size={14} />
                    </button>
                  )}
                </div>
                {isEditingAmount ? (
                  <div className="flex gap-2">
                    <input 
                      type="number"
                      className="w-full px-2 py-1 text-sm border rounded"
                      value={recoveryAmount}
                      onChange={(e) => setRecoveryAmount(e.target.value)}
                    />
                    <button onClick={saveAmount} className="bg-blue-600 text-white px-2 py-1 rounded text-xs">Save</button>
                  </div>
                ) : (
                  <p className="text-2xl font-bold text-blue-800">₹{caseItem.amountRecovered.toLocaleString()}</p>
                )}
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2">
              <div className="p-6 border-r border-gray-100 space-y-4">
                <div className="flex items-center gap-2 text-gray-500 mb-2">
                  <User size={16} />
                  <span className="text-xs font-bold uppercase">Applicant (Worker)</span>
                </div>
                <div>
                  <p className="font-bold text-gray-900">{caseItem.applicantName}</p>
                  <p className="text-sm text-blue-600 font-medium">{caseItem.applicantPhones.join(', ')}</p>
                  <div className="flex gap-2 mt-2">
                    <MapPin size={14} className="text-gray-400 shrink-0 mt-0.5" />
                    <p className="text-sm text-gray-600">{caseItem.applicantAddress}</p>
                  </div>
                </div>
              </div>
              <div className="p-6 space-y-4">
                <div className="flex items-center gap-2 text-gray-500 mb-2">
                  <Building size={16} />
                  <span className="text-xs font-bold uppercase">Management (Company)</span>
                </div>
                <div>
                  <p className="font-bold text-gray-900">{caseItem.managementName}</p>
                  <p className="text-sm text-gray-700">POC: <span className="font-medium">{caseItem.managementPerson}</span></p>
                  <p className="text-sm text-blue-600 font-medium">{caseItem.managementPhone}</p>
                  <div className="flex gap-2 mt-2">
                    <MapPin size={14} className="text-gray-400 shrink-0 mt-0.5" />
                    <p className="text-sm text-gray-600">{caseItem.managementAddress}</p>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Activity Log / Notes Placeholder */}
          <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-6">
            <h3 className="font-bold text-gray-800 mb-4">Case History & Evidence</h3>
            <div className="space-y-4">
              <div className="p-4 bg-gray-50 rounded-lg text-sm text-gray-500 text-center border-2 border-dashed border-gray-200">
                <p>Drag and drop documents here (Worker Statements, Payslips, Memos)</p>
                <button className="mt-2 text-blue-600 font-medium hover:underline">Browse files</button>
              </div>
            </div>
          </div>
        </div>

        {/* Right Column: Hearing Schedule */}
        <div className="space-y-6">
          <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
            <div className="p-4 bg-slate-50 border-b border-gray-100 flex justify-between items-center">
              <h3 className="font-bold text-slate-800 flex items-center gap-2">
                <Calendar size={18} className="text-slate-500" />
                Joint Meetings
              </h3>
              <button 
                onClick={() => setIsAddingHearing(true)}
                className="p-1 hover:bg-slate-200 rounded text-slate-600 transition-colors"
              >
                <Plus size={20} />
              </button>
            </div>

            <div className="p-4 space-y-4">
              {isAddingHearing && (
                <div className="p-4 bg-blue-50 rounded-lg border border-blue-100 space-y-3">
                  <div>
                    <label className="block text-[10px] font-bold text-blue-600 uppercase mb-1">Date & Time</label>
                    <input 
                      type="datetime-local" 
                      className="w-full text-sm p-2 border rounded"
                      value={newHearing.date}
                      onChange={(e) => setNewHearing({...newHearing, date: e.target.value})}
                    />
                  </div>
                  <div>
                    <label className="block text-[10px] font-bold text-blue-600 uppercase mb-1">Remarks</label>
                    <textarea 
                      className="w-full text-sm p-2 border rounded resize-none"
                      rows={2}
                      value={newHearing.remarks}
                      onChange={(e) => setNewHearing({...newHearing, remarks: e.target.value})}
                    />
                  </div>
                  <div className="flex gap-2">
                    <button 
                      onClick={handleAddHearing}
                      className="flex-1 bg-blue-600 text-white py-1.5 rounded text-xs font-bold"
                    >
                      Schedule
                    </button>
                    <button 
                      onClick={() => setIsAddingHearing(false)}
                      className="px-3 bg-white border border-gray-300 rounded text-xs"
                    >
                      Cancel
                    </button>
                  </div>
                </div>
              )}

              <div className="space-y-4">
                {caseItem.hearings.length > 0 ? caseItem.hearings.map((h, i) => (
                  <div key={h.id} className="relative pl-6 pb-4 last:pb-0">
                    {i !== caseItem.hearings.length - 1 && (
                      <div className="absolute left-[9px] top-6 bottom-0 w-0.5 bg-gray-100"></div>
                    )}
                    <div className={`absolute left-0 top-1.5 w-5 h-5 rounded-full border-4 border-white shadow-sm flex items-center justify-center ${
                      h.isCompleted ? 'bg-emerald-500' : 'bg-blue-500'
                    }`}>
                    </div>
                    <div>
                      <div className="flex justify-between items-start">
                        <p className="text-sm font-bold text-gray-900">{new Date(h.date).toLocaleDateString('en-IN', {
                          day: 'numeric', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit'
                        })}</p>
                        <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded ${
                          h.isCompleted ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'
                        }`}>
                          {h.isCompleted ? 'COMPLETED' : 'UPCOMING'}
                        </span>
                      </div>
                      <p className="text-xs text-gray-500 mt-1">{h.remarks || 'No remarks added'}</p>
                    </div>
                  </div>
                )) : (
                  <div className="text-center py-8 text-gray-400">
                    <Clock size={32} className="mx-auto mb-2 opacity-20" />
                    <p className="text-xs">No joint meetings scheduled yet</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CaseDetails;

export enum CaseStatus {
  OPEN = 'Open',
  CLOSED = 'Closed',
  PENDING = 'Pending'
}

export interface Hearing {
  id: string;
  date: string;
  remarks: string;
  isCompleted: boolean;
}

export interface LaborCase {
  id: string;
  fileNumber: string; // Format: A/0000/202X
  receivedDate: string;
  section: string;

  applicantName: string;
  applicantPhones: string[];
  applicantEmail: string; // New field
  applicantAddress: string;

  managementName: string;
  managementPerson: string;
  managementPhone: string;
  managementEmail: string; // New field
  managementAddress: string;

  subject: string;
  amountRecovered: number;
  status: CaseStatus;

  hearings: Hearing[];
  createdAt: string;
}

export type ViewType = 'dashboard' | 'create' | 'details' | 'notice' | 'settings';

import React, { useState, useEffect } from 'react';
import { Save, Link, Bell, Shield, Database } from 'lucide-react';

const Settings: React.FC = () => {
  const [webhookUrl, setWebhookUrl] = useState('');
  const [isSaved, setIsSaved] = useState(false);

  useEffect(() => {
    const savedUrl = localStorage.getItem('make_webhook_url');
    if (savedUrl) setWebhookUrl(savedUrl);
  }, []);

  const handleSave = () => {
    localStorage.setItem('make_webhook_url', webhookUrl);
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-gray-900">System Settings</h1>
        <p className="text-gray-500">Configure integrations and application behavior.</p>
      </div>

      <div className="grid grid-cols-1 gap-6">
        {/* Automation Integration */}
        <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
          <div className="p-6 border-b border-gray-100 flex items-center gap-3 bg-slate-50">
            <Link className="text-blue-600" size={24} />
            <div>
              <h2 className="font-bold text-gray-800">Make.com Integration</h2>
              <p className="text-xs text-gray-500">Trigger WhatsApp and Email notifications automatically.</p>
            </div>
          </div>
          <div className="p-6 space-y-4">
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Notice Webhook URL</label>
              <input 
                type="text"
                placeholder="https://hook.us1.make.com/your-unique-id"
                className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-mono text-sm"
                value={webhookUrl}
                onChange={(e) => setWebhookUrl(e.target.value)}
              />
              <p className="mt-2 text-xs text-gray-500">
                Data sent to this URL includes: File Number, Applicant Details, Management Details, and Notice Content.
              </p>
            </div>
            <div className="flex justify-end pt-2">
              <button 
                onClick={handleSave}
                className={`flex items-center gap-2 px-6 py-2 rounded-lg font-bold text-sm transition-all ${
                  isSaved ? 'bg-emerald-600 text-white' : 'bg-blue-600 text-white hover:bg-blue-700'
                }`}
              >
                <Save size={18} />
                {isSaved ? 'Settings Saved' : 'Save Configuration'}
              </button>
            </div>
          </div>
        </div>

        {/* Placeholder cards for other settings */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 opacity-60">
          <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm flex items-center gap-4">
            <div className="p-3 bg-orange-100 text-orange-600 rounded-lg">
              <Bell size={20} />
            </div>
            <div>
              <h3 className="font-bold text-sm">Notifications</h3>
              <p className="text-xs text-gray-500">Manage internal staff alerts</p>
            </div>
          </div>
          <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm flex items-center gap-4">
