import React, { useState } from 'react';
import { LaborCase } from '../types';
import { Printer, ArrowLeft, Send, Mail, MessageSquare, CheckCircle, AlertCircle, Loader2 } from 'lucide-react';

interface NoticePreviewProps {
  caseItem: LaborCase;
  onBack: () => void;
}

const NoticePreview: React.FC<NoticePreviewProps> = ({ caseItem, onBack }) => {
  const [isSending, setIsSending] = useState(false);
  const [sendStatus, setSendStatus] = useState<'idle' | 'success' | 'error'>('idle');

  const handlePrint = () => {
    window.print();
  };

  const handleSendAutomation = async () => {
    const webhookUrl = localStorage.getItem('make_webhook_url');
    if (!webhookUrl) {
      alert("Please configure the Make.com Webhook URL in Settings first!");
      return;
    }

    setIsSending(true);
    setSendStatus('idle');

    try {
      const payload = {
        timestamp: new Date().toISOString(),
        fileNumber: caseItem.fileNumber,
        section: caseItem.section,
        subject: caseItem.subject,
        applicant: {
          name: caseItem.applicantName,
          phone: caseItem.applicantPhones[0],
          email: caseItem.applicantEmail,
          address: caseItem.applicantAddress
        },
        management: {
          name: caseItem.managementName,
          person: caseItem.managementPerson,
          phone: caseItem.managementPhone,
          email: caseItem.managementEmail,
          address: caseItem.managementAddress
        },
        hearingDate: caseItem.hearings.length > 0 ? caseItem.hearings[caseItem.hearings.length-1].date : 'Pending',
        noticeContent: `JOINT MEETING NOTICE: You are requested to attend a joint meeting regarding ${caseItem.subject} on ${caseItem.hearings.length > 0 ? caseItem.hearings[caseItem.hearings.length-1].date : 'TBD'}.`
      };

      const response = await fetch(webhookUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      if (response.ok) {
        setSendStatus('success');
      } else {
        setSendStatus('error');
      }
    } catch (error) {
      console.error("Webhook Error:", error);
      setSendStatus('error');
    } finally {
      setIsSending(false);
      setTimeout(() => setSendStatus('idle'), 5000);
    }
  };

  const today = new Date().toLocaleDateString('en-IN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric'
  });

  return (
    <div className="max-w-5xl mx-auto pb-12">
      <div className="flex justify-between items-center mb-6 no-print">
        <button 
          onClick={onBack}
          className="flex items-center gap-2 text-gray-600 hover:text-gray-900 font-medium"
        >
          <ArrowLeft size={20} />
          Back to Case
        </button>
        <div className="flex gap-2">
          <button 
            disabled={isSending}
            onClick={handleSendAutomation}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95 ${
              sendStatus === 'success' ? 'bg-emerald-600 text-white' :
              sendStatus === 'error' ? 'bg-red-600 text-white' :
              'bg-indigo-600 text-white hover:bg-indigo-700'
            }`}
          >
            {isSending ? <Loader2 size={18} className="animate-spin" /> : 
             sendStatus === 'success' ? <CheckCircle size={18} /> :
             sendStatus === 'error' ? <AlertCircle size={18} /> :
             <Send size={18} />}
            {isSending ? 'Triggering Make.com...' : 
             sendStatus === 'success' ? 'Automation Sent!' :
             sendStatus === 'error' ? 'Failed to Send' :
             'Send to WhatsApp & Email'}
          </button>

          <button 
            onClick={handlePrint}
            className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-300 rounded-lg text-sm font-medium hover:bg-gray-50 shadow-sm"
          >
            <Printer size={18} />
            Print Notice
          </button>
        </div>
      </div>

      {/* Letterhead Preview */}
      <div className="bg-white p-[1in] md:p-[2in] shadow-lg mx-auto border border-gray-200 print:shadow-none print:border-none print:p-0 min-h-[11in] w-full max-w-[8.5in]">
        <div className="text-center border-b-2 border-gray-800 pb-4 mb-8">
          <h1 className="text-2xl font-bold uppercase tracking-wide">Government of Telangana</h1>
          <h2 className="text-lg font-semibold mt-1">Labour Department</h2>
          <p className="text-sm">Office of the Assistant Commissioner of Labour, Rangareddy District</p>
          <p className="text-xs italic mt-1 text-gray-600">Integrated Welfare Hub, Phase II, Rangareddy</p>
        </div>

        <div className="flex justify-between items-start mb-10">
          <div className="space-y-1">
            <p className="font-semibold text-sm">Case No: <span className="font-normal underline ml-1">{caseItem.fileNumber}</span></p>
            <p className="font-semibold text-sm">Section: <span className="font-normal ml-1">{caseItem.section}</span></p>
          </div>
          <div className="text-right">
            <p className="text-sm font-semibold">Dated: <span className="font-normal ml-1">{today}</span></p>
          </div>
        </div>

        <div className="mb-10 text-sm">
          <h3 className="font-bold underline mb-3 uppercase">JOINT MEETING NOTICE</h3>

          <div className="space-y-4">
            <div>
              <p className="font-bold">To,</p>
              <div className="ml-8 mt-2 leading-relaxed">
                <p>The Management,</p>
