                  <span className="text-3xl font-black text-blue-900 tracking-tighter">₹{caseItem.amountRecovered.toLocaleString()}</span>
                  <button onClick={() => setIsEditingAmount(true)} className="text-blue-400 hover:text-blue-600">
                    <Edit3 size={16} />
