    applicantName: '',
    applicantPhone: '',
    applicantEmail: '',
    applicantAddress: '',
    managementName: '',
    managementPerson: '',
    managementPhone: '',
    managementEmail: '',
    managementAddress: '',
    subject: '',
    amountRecovered: '0'
