import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  PlusCircle, 
  Users, 
  Settings as SettingsIcon, 
  FileText, 
  Search,
  Bell,
  LogOut,
  Menu,
  Shield,
  Briefcase
} from 'lucide-react';
import { LaborCase, ViewType, CaseStatus } from './types.ts';
import Dashboard from './components/Dashboard.tsx';
import CaseForm from './components/CaseForm.tsx';
import CaseDetails from './components/CaseDetails.tsx';
import NoticePreview from './components/NoticePreview.tsx';
import Settings from './components/Settings.tsx';
import PublicPortal from './components/PublicPortal.tsx';
import Login from './components/Login.tsx';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('portal');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [selectedCaseId, setSelectedCaseId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [cases, setCases] = useState<LaborCase[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    const savedCases = localStorage.getItem('labor_cases');
    if (savedCases) {
      try {
        const parsed = JSON.parse(savedCases);
        setCases(Array.isArray(parsed) ? parsed : []);
      } catch (e) {
        console.error("Failed to parse local cases", e);
        setCases([]);
      }
    } else {
      const mockCases: LaborCase[] = [
        {
          id: '1',
          fileNumber: 'TG/LC/2025/001',
          receivedDate: '2025-01-15',
          section: 'Minimum Wages',
          applicantName: 'Rajesh Kumar Yadav',
          applicantPhones: ['9876543210'],
          applicantEmail: 'rajesh.yadav@example.com',
          applicantAddress: 'Plot 45, Jubilee Hills, Hyderabad',
          managementName: 'Sunrise Textiles Pvt Ltd',
          managementPerson: 'Sri K. Venkatesh',
          managementPhone: '8887776660',
          managementEmail: 'hr@sunrisetextiles.com',
          managementAddress: 'HITEC City, Phase 2, Hyderabad',
          subject: 'Unpaid Wages – 6 Months Arrears',
          amountRecovered: 148000,
          status: CaseStatus.OPEN,
          hearings: [
            { id: 'h1', date: '2025-02-10T10:30', remarks: 'Case registered. Notice issued to Management.', isCompleted: true }
          ],
          createdAt: new Date().toISOString()
        }
      ];
      setCases(mockCases);
      localStorage.setItem('labor_cases', JSON.stringify(mockCases));
    }
  }, []);

  const saveCases = (updatedCases: LaborCase[]) => {
    setCases(updatedCases);
    localStorage.setItem('labor_cases', JSON.stringify(updatedCases));
  };

  const handleCreateCase = (newCase: LaborCase) => {
    saveCases([newCase, ...cases]);
    setActiveView('dashboard');
  };

  const handleUpdateCase = (updatedCase: LaborCase) => {
    saveCases(cases.map(c => c.id === updatedCase.id ? updatedCase : c));
  };

  const handleLogin = (success: boolean) => {
    if (success) {
      setIsLoggedIn(true);
      setActiveView('dashboard');
    }
  };

  const filteredCases = useMemo(() => {
    return cases.filter(c => 
      c.fileNumber.toLowerCase().includes(searchQuery.toLowerCase()) ||
      c.applicantName.toLowerCase().includes(searchQuery.toLowerCase()) ||
      c.managementName.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [cases, searchQuery]);

  const selectedCase = useMemo(() => {
    return cases.find(c => c.id === selectedCaseId) || null;
  }, [cases, selectedCaseId]);

  const renderView = () => {
    if (activeView === 'portal') {
      return <PublicPortal cases={cases} onAdminAccess={() => setActiveView('login')} />;
    }

    if (activeView === 'login' || !isLoggedIn) {
      return <Login onLogin={handleLogin} onBack={() => setActiveView('portal')} />;
    }

    switch (activeView) {
      case 'dashboard':
        return (
          <Dashboard 
            cases={filteredCases} 
            onViewDetails={(id) => {
              setSelectedCaseId(id);
              setActiveView('details');
            }}
            onGenerateNotice={(id) => {
              setSelectedCaseId(id);
              setActiveView('notice');
            }}
          />
        );
      case 'create':
        return <CaseForm onSubmit={handleCreateCase} onCancel={() => setActiveView('dashboard')} />;
      case 'details':
        return selectedCase ? (
          <CaseDetails 
            caseItem={selectedCase} 
            onUpdate={handleUpdateCase} 
            onBack={() => setActiveView('dashboard')} 
            onNotice={() => setActiveView('notice')}
          />
        ) : null;
      case 'notice':
        return selectedCase ? (
          <NoticePreview 
            caseItem={selectedCase} 
            onBack={() => setActiveView('details')} 
          />
        ) : null;
      case 'settings':
        return <Settings />;
      default:
        return <PublicPortal cases={cases} onAdminAccess={() => setActiveView('login')} />;
    }
  };

  const showSidebar = isLoggedIn && activeView !== 'portal' && activeView !== 'login';

  return (
    <div className="min-h-screen flex bg-[#FDFBF7]">
      {showSidebar && (
        <aside className={`
          ${isSidebarOpen ? 'w-72' : 'w-20'} 
          bg-[#0A1628] text-[#F5F0E8] transition-all duration-300 flex flex-col no-print border-r border-[#C9A84C]/20
        `}>
          <div className="p-8 flex items-center gap-4">
            <div className="w-12 h-12 bg-[#C9A84C]/20 border-2 border-[#C9A84C] rounded-xl flex items-center justify-center font-bold text-2xl text-[#C9A84C] shadow-lg shadow-[#C9A84C]/10">
              <Shield size={24} />
            </div>
            {isSidebarOpen && (
              <div className="flex flex-col">
                <span className="serif font-black text-lg text-[#C9A84C] leading-none tracking-tight">LABOUR ADMIN</span>
                <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mt-1">First Principles OS</span>
              </div>
            )}
          </div>

          <nav className="flex-1 mt-6 px-4 space-y-1">
            {[
              { id: 'dashboard', label: 'Command Center', icon: LayoutDashboard },
              { id: 'create', label: 'New Identity Record', icon: PlusCircle },
              { id: 'settings', label: 'System Logic', icon: SettingsIcon },
            ].map((item) => (
              <button 
                key={item.id}
                onClick={() => setActiveView(item.id as ViewType)}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                  activeView === item.id 
                    ? 'bg-[#C9A84C]/15 text-[#C9A84C] border border-[#C9A84C]/30 shadow-sm' 
                    : 'text-slate-500 hover:bg-white/5 hover:text-slate-200'
                }`}
              >
                <item.icon size={20} />
                {isSidebarOpen && <span className="text-sm font-bold">{item.label}</span>}
              </button>
            ))}
          </nav>

          <div className="p-6 border-t border-white/5 bg-[#0F2044]">
            <button 
              onClick={() => {
                setIsLoggedIn(false);
                setActiveView('portal');
              }}
              className="w-full flex items-center justify-center gap-3 px-3 py-2.5 rounded-xl bg-red-500/10 text-red-400 hover:bg-red-500 hover:text-white transition-all text-xs font-bold"
            >
              <LogOut size={16} />
              {isSidebarOpen && <span>TERMINATE SESSION</span>}
            </button>
          </div>
        </aside>
      )}

      <main className="flex-1 flex flex-col overflow-hidden">
        {showSidebar && (
          <header className="h-20 bg-white/80 backdrop-blur-md border-b border-[#C9A84C]/10 flex items-center justify-between px-8 no-print">
            <div className="flex items-center gap-6 flex-1">
              <button 
                onClick={() => setIsSidebarOpen(!isSidebarOpen)}
                className="p-2 hover:bg-slate-100 rounded-lg text-[#0A1628] transition-colors"
              >
                <Menu size={24} />
              </button>
              <div className="relative max-w-xl w-full">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                  type="text" 
                  placeholder="Query file identity, petitioner, or respondent..."
                  className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-[#C9A84C] focus:bg-white text-sm font-medium transition-all"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>
            </div>

            <div className="flex items-center gap-6">
              <div className="hidden lg:flex flex-col text-right">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Active Project</p>
                <p className="text-xs font-black text-[#0A1628]">Office of the Asst. Commissioner of Labour</p>
              </div>
              <button className="relative p-2.5 bg-slate-100 text-[#0A1628] hover:bg-slate-200 rounded-xl transition-all">
                <Bell size={20} />
                <span className="absolute top-2 right-2 w-2.5 h-2.5 bg-[#C9A84C] rounded-full border-2 border-white"></span>
              </button>
            </div>
          </header>
        )}

        <div className={`flex-1 overflow-y-auto ${!showSidebar ? '' : 'p-8'} custom-scrollbar`}>
          {renderView()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { LaborCase, CaseStatus } from '../types';
import { 
  Save, X, Phone, User, Building, MapPin, 
  Calendar, Info, FileText, Mail, ChevronDown,
  Clock, Store, Briefcase, Baby, HardHat, Scale,
  PlusCircle, ChevronRight, ChevronLeft, CheckCircle2
} from 'lucide-react';

interface CaseFormProps {
  onSubmit: (newCase: LaborCase) => void;
  onCancel: () => void;
}

const SectionSelect = ({ value, onChange }: { value: string, onChange: (v: string) => void }) => {
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  const options = [
    { label: 'Minimum Wages', icon: Clock, color: 'text-blue-500' },
    { label: 'Payment of Wages', icon: Scale, color: 'text-emerald-500' },
    { label: 'Shops & Establishments', icon: Store, color: 'text-orange-500' },
    { label: 'Maternity Benefit', icon: Baby, color: 'text-pink-500' },
    { label: 'Contract Labour', icon: HardHat, color: 'text-amber-500' },
    { label: 'Industrial Relations', icon: Briefcase, color: 'text-indigo-500' },
  ];

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const selectedOption = options.find(o => o.label === value) || options[0];

  return (
    <div className="relative" ref={containerRef}>
      <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 ml-1 tracking-widest">Case Section</label>
      <button
        type="button"
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center justify-between px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl hover:border-[#C9A84C] transition-all text-sm group"
      >
        <div className="flex items-center gap-3">
          <selectedOption.icon size={18} className={selectedOption.color} />
          <span className="font-bold text-slate-700">{selectedOption.label}</span>
        </div>
        <ChevronDown size={18} className={`text-slate-400 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute z-50 w-full mt-2 bg-white border border-slate-200 rounded-2xl shadow-2xl overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
          <div className="p-2">
            {options.map((option) => (
              <button
                key={option.label}
                type="button"
                onClick={() => {
                  onChange(option.label);
                  setIsOpen(false);
                }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm transition-all ${
                  value === option.label ? 'bg-[#0A1628] text-[#C9A84C]' : 'hover:bg-slate-50 text-slate-600'
                }`}
              >
                <option.icon size={18} className={value === option.label ? 'text-[#C9A84C]' : option.color} />
                <span className="flex-1 text-left font-bold">{option.label}</span>
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

const CaseForm: React.FC<CaseFormProps> = ({ onSubmit, onCancel }) => {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    fileNumber: `A/${Math.floor(Math.random() * 9000 + 1000)}/2025`,
    receivedDate: new Date().toISOString().split('T')[0],
    section: 'Minimum Wages',
    applicantName: '',
    applicantPhone: '',
    applicantEmail: '',
    applicantAddress: '',
    managementName: '',
    managementPerson: '',
    managementPhone: '',
    managementEmail: '',
    managementAddress: '',
    subject: '',
    amountRecovered: '0'
  });

  const steps = [
    { id: 1, title: 'Classification', sub: 'File Identity & Section' },
    { id: 2, title: 'Petitioner', sub: 'Applicant Credentials' },
    { id: 3, title: 'Respondent', sub: 'Management Entities' },
    { id: 4, title: 'Resolution', sub: 'Conflict & Quantum' }
  ];

  const handleNext = () => {
    if (currentStep < 4) setCurrentStep(currentStep + 1);
  };

  const handleBack = () => {
    if (currentStep > 1) setCurrentStep(currentStep - 1);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (currentStep < 4) {
      handleNext();
      return;
    }

    const newCase: LaborCase = {
      id: Date.now().toString(),
      fileNumber: formData.fileNumber,
      receivedDate: formData.receivedDate,
      section: formData.section,
      applicantName: formData.applicantName,
      applicantPhones: [formData.applicantPhone],
      applicantEmail: formData.applicantEmail,
      applicantAddress: formData.applicantAddress,
      managementName: formData.managementName,
      managementPerson: formData.managementPerson,
      managementPhone: formData.managementPhone,
      managementEmail: formData.managementEmail,
      managementAddress: formData.managementAddress,
      subject: formData.subject,
      amountRecovered: parseFloat(formData.amountRecovered),
      status: CaseStatus.OPEN,
      hearings: [],
      createdAt: new Date().toISOString()
    };
    onSubmit(newCase);
  };

  return (
    <div className="max-w-4xl mx-auto pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-12 gap-6">
        <div>
          <h1 className="serif text-3xl font-black text-[#0A1628] flex items-center gap-3">
            <div className="p-2 bg-[#0A1628] rounded-xl text-[#C9A84C] shadow-lg shadow-[#0A1628]/10">
              <PlusCircle size={24} />
            </div>
            Registry Initiation
          </h1>
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.3em] mt-2">New Identity Record Creation • First Principles</p>
        </div>
        <button 
          onClick={onCancel}
          className="p-3 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-2xl transition-all self-start md:self-auto"
        >
          <X size={24} />
        </button>
      </div>

      <div className="flex items-start justify-between mb-12 relative px-4">
        <div className="absolute top-5 left-10 right-10 h-0.5 bg-slate-100 -z-10" />
        {steps.map((step) => (
          <div key={step.id} className="flex flex-col items-center gap-3 relative z-10">
            <div 
              className={`w-10 h-10 rounded-full flex items-center justify-center font-black text-sm transition-all duration-500 border-4 border-[#FDFBF7] shadow-sm ${
                currentStep === step.id 
                  ? 'bg-[#0A1628] text-[#C9A84C] scale-110 shadow-xl' 
                  : currentStep > step.id 
                    ? 'bg-[#C9A84C] text-[#0A1628]' 
                    : 'bg-slate-100 text-slate-400'
              }`}
            >
              {currentStep > step.id ? <CheckCircle2 size={18} /> : step.id}
            </div>
            <div className="text-center">
              <p className={`text-[10px] font-black uppercase tracking-widest ${currentStep >= step.id ? 'text-[#0A1628]' : 'text-slate-300'}`}>
                {step.title}
              </p>
              <p className="text-[8px] font-bold text-slate-400 uppercase tracking-tighter mt-0.5 hidden md:block">
                {step.sub}
              </p>
            </div>
          </div>
        ))}
      </div>

      <form onSubmit={handleSubmit} className="space-y-8">
        <div className="bg-white rounded-[2rem] border border-slate-200 shadow-2xl shadow-[#0A1628]/5 overflow-hidden min-h-[400px] flex flex-col">
          <div className="h-1.5 w-full bg-[#C9A84C]/20">
            <div 
              className="h-full bg-[#0A1628] transition-all duration-700 ease-out" 
              style={{ width: `${(currentStep / 4) * 100}%` }} 
            />
          </div>

          <div className="p-10 flex-1 flex flex-col justify-center animate-in fade-in slide-in-from-bottom-4 duration-500">
            {currentStep === 1 && (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-6">
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 ml-1 tracking-widest">Protocol File Number</label>
                    <div className="relative group">
                      <FileText className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-[#C9A84C] transition-colors" size={18} />
                      <input 
                        required
                        className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-[#C9A84C] focus:bg-white transition-all text-sm font-bold outline-none" 
                        value={formData.fileNumber}
                        onChange={(e) => setFormData({...formData, fileNumber: e.target.value})}
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 ml-1 tracking-widest">Identity Receipt Date</label>
                    <div className="relative group">
                      <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-[#C9A84C] transition-colors" size={18} />
                      <input 
                        required
                        type="date"
                        className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-[#C9A84C] focus:bg-white transition-all text-sm font-bold outline-none" 
                        value={formData.receivedDate}
                        onChange={(e) => setFormData({...formData, receivedDate: e.target.value})}
                      />
                    </div>
                  </div>
                </div>
                <div className="flex flex-col justify-end">
                  <SectionSelect 
                    value={formData.section} 
                    onChange={(v) => setFormData({...formData, section: v})} 
                  />
                </div>
              </div>
            )}

            {currentStep === 2 && (
              <div className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="md:col-span-2">
                    <label className="block text-[10px] font-black text-slate-400 uppercase mb-2 ml-1 tracking-widest">Petitioner Legal Name</label>
                    <div className="relative group">
                      <User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-[#C9A84C]" size={18} />
                      <input 
                        required
                        placeholder="e.g. Sri A. Rajesh"
