}

export type ViewType = 'portal' | 'login' | 'dashboard' | 'create' | 'details' | 'notice' | 'settings';

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  PlusCircle, 
  Users, 
  Settings as SettingsIcon, 
  FileText, 
  Search,
  Bell,
  LogOut,
  Menu,
  Shield,
  Briefcase
} from 'lucide-react';
import { LaborCase, ViewType, CaseStatus } from './types.ts';
import Dashboard from './components/Dashboard.tsx';
import CaseForm from './components/CaseForm.tsx';
import CaseDetails from './components/CaseDetails.tsx';
import NoticePreview from './components/NoticePreview.tsx';
import Settings from './components/Settings.tsx';
import PublicPortal from './components/PublicPortal.tsx';
import Login from './components/Login.tsx';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('portal');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [selectedCaseId, setSelectedCaseId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [cases, setCases] = useState<LaborCase[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    const savedCases = localStorage.getItem('labor_cases');
    if (savedCases) {
      try {
        const parsed = JSON.parse(savedCases);
        setCases(Array.isArray(parsed) ? parsed : []);
      } catch (e) {
        console.error("Failed to parse local cases", e);
        setCases([]);
      }
    } else {
      const mockCases: LaborCase[] = [
        {
          id: '1',
          fileNumber: 'TG/LC/2025/001',
          receivedDate: '2025-01-15',
          section: 'Minimum Wages',
          applicantName: 'Rajesh Kumar Yadav',
          applicantPhones: ['9876543210'],
          applicantEmail: 'rajesh.yadav@example.com',
          applicantAddress: 'Plot 45, Jubilee Hills, Hyderabad',
          managementName: 'Sunrise Textiles Pvt Ltd',
          managementPerson: 'Sri K. Venkatesh',
          managementPhone: '8887776660',
          managementEmail: 'hr@sunrisetextiles.com',
          managementAddress: 'HITEC City, Phase 2, Hyderabad',
          subject: 'Unpaid Wages – 6 Months Arrears',
          amountRecovered: 148000,
          status: CaseStatus.OPEN,
          hearings: [
            { id: 'h1', date: '2025-02-10T10:30', remarks: 'Case registered. Notice issued to Management.', isCompleted: true }
          ],
          createdAt: new Date().toISOString()
        }
      ];
      setCases(mockCases);
      localStorage.setItem('labor_cases', JSON.stringify(mockCases));
    }
  }, []);

  const saveCases = (updatedCases: LaborCase[]) => {
    setCases(updatedCases);
    localStorage.setItem('labor_cases', JSON.stringify(updatedCases));
  };

  const handleCreateCase = (newCase: LaborCase) => {
    saveCases([newCase, ...cases]);
    setActiveView('dashboard');
  };

  const handleUpdateCase = (updatedCase: LaborCase) => {
    saveCases(cases.map(c => c.id === updatedCase.id ? updatedCase : c));
  };

  const handleArchiveCase = (id: string) => {
    saveCases(cases.map(c => c.id === id ? { ...c, status: CaseStatus.ARCHIVED } : c));
  };

  const handleLogin = (success: boolean) => {
    if (success) {
      setIsLoggedIn(true);
      setActiveView('dashboard');
    }
  };

  const filteredCases = useMemo(() => {
    return cases.filter(c => 
      c.fileNumber.toLowerCase().includes(searchQuery.toLowerCase()) ||
      c.applicantName.toLowerCase().includes(searchQuery.toLowerCase()) ||
      c.managementName.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [cases, searchQuery]);

  const selectedCase = useMemo(() => {
    return cases.find(c => c.id === selectedCaseId) || null;
  }, [cases, selectedCaseId]);

  const renderView = () => {
    if (activeView === 'portal') {
      return <PublicPortal cases={cases} onAdminAccess={() => setActiveView('login')} />;
    }

    if (activeView === 'login' || !isLoggedIn) {
      return <Login onLogin={handleLogin} onBack={() => setActiveView('portal')} />;
    }

    switch (activeView) {
      case 'dashboard':
        return (
          <Dashboard 
            cases={filteredCases} 
            onViewDetails={(id) => {
              setSelectedCaseId(id);
              setActiveView('details');
            }}
            onGenerateNotice={(id) => {
              setSelectedCaseId(id);
              setActiveView('notice');
            }}
            onArchive={handleArchiveCase}
          />
        );
      case 'create':
        return <CaseForm onSubmit={handleCreateCase} onCancel={() => setActiveView('dashboard')} />;
      case 'details':
        return selectedCase ? (
          <CaseDetails 
            caseItem={selectedCase} 
            onUpdate={handleUpdateCase} 
            onBack={() => setActiveView('dashboard')} 
            onNotice={() => setActiveView('notice')}
          />
        ) : null;
      case 'notice':
        return selectedCase ? (
          <NoticePreview 
            caseItem={selectedCase} 
            onBack={() => setActiveView('details')} 
          />
        ) : null;
      case 'settings':
        return <Settings />;
      default:
        return <PublicPortal cases={cases} onAdminAccess={() => setActiveView('login')} />;
    }
  };

  const showSidebar = isLoggedIn && activeView !== 'portal' && activeView !== 'login';

  return (
    <div className="min-h-screen flex bg-[#FDFBF7]">
      {showSidebar && (
        <aside className={`
          ${isSidebarOpen ? 'w-72' : 'w-20'} 
          bg-[#0A1628] text-[#F5F0E8] transition-all duration-300 flex flex-col no-print border-r border-[#C9A84C]/20
        `}>
          <div className="p-8 flex items-center gap-4">
            <div className="w-12 h-12 bg-[#C9A84C]/20 border-2 border-[#C9A84C] rounded-xl flex items-center justify-center font-bold text-2xl text-[#C9A84C] shadow-lg shadow-[#C9A84C]/10">
              <Shield size={24} />
            </div>
            {isSidebarOpen && (
              <div className="flex flex-col">
                <span className="serif font-black text-lg text-[#C9A84C] leading-none tracking-tight">LABOUR ADMIN</span>
                <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mt-1">First Principles OS</span>
              </div>
            )}
          </div>

          <nav className="flex-1 mt-6 px-4 space-y-1">
            {[
              { id: 'dashboard', label: 'Command Center', icon: LayoutDashboard },
              { id: 'create', label: 'New Identity Record', icon: PlusCircle },
              { id: 'settings', label: 'System Logic', icon: SettingsIcon },
            ].map((item) => (
              <button 
                key={item.id}
                onClick={() => setActiveView(item.id as ViewType)}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                  activeView === item.id 
                    ? 'bg-[#C9A84C]/15 text-[#C9A84C] border border-[#C9A84C]/30 shadow-sm' 
                    : 'text-slate-500 hover:bg-white/5 hover:text-slate-200'
                }`}
              >
                <item.icon size={20} />
                {isSidebarOpen && <span className="text-sm font-bold">{item.label}</span>}
              </button>
            ))}
          </nav>

          <div className="p-6 border-t border-white/5 bg-[#0F2044]">
            <button 
              onClick={() => {
                setIsLoggedIn(false);
                setActiveView('portal');
              }}
              className="w-full flex items-center justify-center gap-3 px-3 py-2.5 rounded-xl bg-red-500/10 text-red-400 hover:bg-red-500 hover:text-white transition-all text-xs font-bold"
            >
              <LogOut size={16} />
              {isSidebarOpen && <span>TERMINATE SESSION</span>}
            </button>
          </div>
        </aside>
      )}

      <main className="flex-1 flex flex-col overflow-hidden">
        {showSidebar && (
          <header className="h-20 bg-white/80 backdrop-blur-md border-b border-[#C9A84C]/10 flex items-center justify-between px-8 no-print">
            <div className="flex items-center gap-6 flex-1">
              <button 
                onClick={() => setIsSidebarOpen(!isSidebarOpen)}
                className="p-2 hover:bg-slate-100 rounded-lg text-[#0A1628] transition-colors"
              >
                <Menu size={24} />
              </button>
              <div className="relative max-w-xl w-full">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                  type="text" 
                  placeholder="Query file identity, petitioner, or respondent..."
                  className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-[#C9A84C] focus:bg-white text-sm font-medium transition-all"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>
            </div>

            <div className="flex items-center gap-6">
              <div className="hidden lg:flex flex-col text-right">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Active Project</p>
                <p className="text-xs font-black text-[#0A1628]">Office of the Asst. Commissioner of Labour</p>
              </div>
              <button className="relative p-2.5 bg-slate-100 text-[#0A1628] hover:bg-slate-200 rounded-xl transition-all">
                <Bell size={20} />
                <span className="absolute top-2 right-2 w-2.5 h-2.5 bg-[#C9A84C] rounded-full border-2 border-white"></span>
              </button>
            </div>
          </header>
        )}

        <div className={`flex-1 overflow-y-auto ${!showSidebar ? '' : 'p-8'} custom-scrollbar`}>
          {renderView()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { LaborCase, CaseStatus } from '../types';
import { 
  FileText, 
  TrendingUp, 
  CheckCircle, 
  AlertCircle, 
  ChevronRight,
  Printer,
  Calendar,
  Layers,
  Search,
  Filter,
  IndianRupee,
  Clock,
  CalendarDays,
  Archive
} from 'lucide-react';

interface DashboardProps {
  cases: LaborCase[];
  onViewDetails: (id: string) => void;
  onGenerateNotice: (id: string) => void;
  onArchive: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ cases, onViewDetails, onGenerateNotice, onArchive }) => {
  const [statusFilter, setStatusFilter] = useState<CaseStatus | 'ALL' | 'ARCHIVED'>('ALL');

  // Temporal Logic for Today and Tomorrow
  const todayStr = new Date().toLocaleDateString('en-CA'); // YYYY-MM-DD format
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  const tomorrowStr = tomorrow.toLocaleDateString('en-CA');

  const todayMeetingsCount = useMemo(() => {
    return cases.reduce((acc, c) => 
      acc + c.hearings.filter(h => h.date.startsWith(todayStr)).length, 0
    );
  }, [cases, todayStr]);

  const tomorrowMeetingsCount = useMemo(() => {
    return cases.reduce((acc, c) => 
      acc + c.hearings.filter(h => h.date.startsWith(tomorrowStr)).length, 0
    );
  }, [cases, tomorrowStr]);

  const stats = [
    { label: 'Atomic Records', value: cases.length, icon: Layers, color: 'blue' },
    { label: 'Capital Recovered', value: `₹${cases.reduce((sum, c) => sum + (c.amountRecovered || 0), 0).toLocaleString()}`, icon: TrendingUp, color: 'gold' },
    { label: "Today's Agenda", value: todayMeetingsCount, icon: Clock, color: 'pulse', sub: 'Active Events' },
    { label: 'Tomorrow Schedule', value: tomorrowMeetingsCount, icon: CalendarDays, color: 'navy', sub: 'Next Cycle' },
    { label: 'Open Conflicts', value: cases.filter(c => c.status === CaseStatus.OPEN).length, icon: AlertCircle, color: 'orange' },
    { label: 'Resolved Events', value: cases.filter(c => c.status === CaseStatus.CLOSED).length, icon: CheckCircle, color: 'emerald' },
  ];

  const displayedCases = useMemo(() => {
    if (statusFilter === 'ALL') {
      // Hide archived by default when viewing 'ALL'
      return cases.filter(c => c.status !== CaseStatus.ARCHIVED);
    }
    if (statusFilter === 'ARCHIVED') {
      return cases.filter(c => c.status === CaseStatus.ARCHIVED);
    }
    return cases.filter(c => c.status === statusFilter);
  }, [cases, statusFilter]);

  const filterOptions = [
    { label: 'All Active', value: 'ALL' },
    { label: 'Open', value: CaseStatus.OPEN },
    { label: 'Pending', value: CaseStatus.PENDING },
    { label: 'Closed', value: CaseStatus.CLOSED },
    { label: 'Archived', value: 'ARCHIVED' },
  ];

  return (
    <div className="space-y-10 max-w-7xl mx-auto">
      {/* Header Atom */}
      <div className="flex justify-between items-center bg-[#0A1628] p-8 rounded-3xl border border-[#C9A84C]/30 shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-20 opacity-5 pointer-events-none">
          <Layers size={200} className="text-[#C9A84C]" />
        </div>
        <div className="relative z-10">
          <h1 className="serif text-4xl font-black text-[#F5F0E8] tracking-tight">COMMAND CENTER</h1>
          <p className="text-[#C9A84C] text-xs font-black uppercase tracking-[0.3em] mt-2">Atomic State Observation • Rangareddy</p>
        </div>
        <div className="flex gap-4 relative z-10">
          <button className="px-6 py-3 bg-[#C9A84C] text-[#0A1628] font-black text-xs uppercase tracking-widest rounded-xl hover:bg-[#F5F0E8] transition-all flex items-center gap-2 shadow-xl shadow-[#C9A84C]/10">
            <Printer size={16} />
            System Audit
          </button>
        </div>
      </div>

      {/* Stats Deconstruction */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-6">
        {stats.map((stat) => (
          <div key={stat.label} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm hover:shadow-xl hover:border-[#C9A84C]/50 transition-all group relative overflow-hidden">
            <div className={`absolute top-0 right-0 w-24 h-24 -mr-8 -mt-8 opacity-5 group-hover:opacity-10 transition-opacity`}>
              <stat.icon size={96} className="text-slate-900" />
            </div>
            <div className="flex justify-between items-start mb-3">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{stat.label}</p>
              {stat.color === 'pulse' && stat.value > 0 && (
                <span className="flex h-2 w-2 rounded-full bg-red-500 animate-pulse"></span>
              )}
            </div>
            <div className="flex items-end justify-between">
              <div>
                <p className={`serif text-4xl font-black ${stat.color === 'gold' ? 'text-[#C9A84C]' : 'text-[#0A1628]'}`}>
                  {stat.value}
                </p>
                {stat.sub && (
                  <p className="text-[8px] font-black text-slate-400 uppercase tracking-tighter mt-1">{stat.sub}</p>
                )}
              </div>
              <div className={`p-2 rounded-lg bg-slate-50 text-slate-400 group-hover:text-[#C9A84C] transition-colors`}>
                <stat.icon size={20} />
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* The List View: The Projection of Reality */}
      <div className="bg-white rounded-3xl border border-slate-200 shadow-2xl overflow-hidden">
        <div className="px-8 py-6 bg-slate-50/50 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <h2 className="serif text-xl font-black text-[#0A1628] flex items-center gap-3">
            <Search size={22} className="text-[#C9A84C]" />
            {statusFilter === 'ARCHIVED' ? 'Archived Records' : 'Active Case Trace'}
          </h2>

          {/* Status Filter Component */}
          <div className="flex items-center gap-2 p-1.5 bg-slate-200/50 rounded-2xl border border-slate-200">
            <div className="px-3 text-[#0A1628] opacity-40">
              <Filter size={14} />
            </div>
            <div className="flex gap-1 overflow-x-auto no-scrollbar">
              {filterOptions.map((opt) => (
                <button
                  key={opt.value}
                  onClick={() => setStatusFilter(opt.value as any)}
                  className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${
                    statusFilter === opt.value
                      ? 'bg-[#0A1628] text-[#C9A84C] shadow-lg'
                      : 'text-slate-500 hover:text-[#0A1628] hover:bg-white'
                  }`}
                >
                  {opt.label}
                </button>
              ))}
            </div>
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-[0.15em] border-b border-slate-100">
                <th className="px-8 py-5">File Identity</th>
                <th className="px-8 py-5">The Actors</th>
                <th className="px-8 py-5">Subject Matter</th>
                <th className="px-8 py-5">Recovered Capital</th>
                <th className="px-8 py-5">Event Pulse</th>
                <th className="px-8 py-5 text-right">Inspect</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {displayedCases.length > 0 ? (
                displayedCases.map((c) => (
                  <tr key={c.id} className={`hover:bg-[#C9A84C]/5 transition-all group cursor-pointer ${c.status === CaseStatus.ARCHIVED ? 'opacity-70' : ''}`} onClick={() => onViewDetails(c.id)}>
                    <td className="px-8 py-6">
                      <div className="flex flex-col">
                        <span className="serif font-black text-[#0A1628] text-lg tracking-tight group-hover:text-[#C9A84C] transition-colors">{c.fileNumber}</span>
                        <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{c.section}</span>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-4">
                        <div className="flex flex-col">
                          <span className="text-sm font-black text-slate-800">{c.applicantName}</span>
                          <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">Petitioner</span>
                        </div>
                        <div className="h-6 w-px bg-slate-200 rotate-12" />
                        <div className="flex flex-col">
                          <span className="text-sm font-black text-slate-800">{c.managementName}</span>
                          <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">Respondent</span>
                        </div>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="max-w-[220px]">
                        <p className="text-xs font-bold text-slate-600 line-clamp-2 italic">"{c.subject}"</p>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-1.5">
                        <div className="p-1.5 bg-[#C9A84C]/10 rounded-lg text-[#C9A84C]">
                          <IndianRupee size={14} />
                        </div>
                        <span className="serif text-lg font-black text-[#0A1628]">
                          {c.amountRecovered.toLocaleString('en-IN')}
                        </span>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-3">
                        <span className={`px-2 py-0.5 rounded text-[8px] font-black uppercase tracking-widest ${
                          c.status === CaseStatus.OPEN ? 'bg-orange-100 text-orange-700' : 
                          c.status === CaseStatus.CLOSED ? 'bg-emerald-100 text-emerald-700' : 
                          c.status === CaseStatus.ARCHIVED ? 'bg-slate-200 text-slate-500' :
                          'bg-slate-100 text-slate-700'
                        }`}>
                          {c.status}
                        </span>
                        {c.hearings.length > 0 ? (
                          <div className="flex items-center gap-2">
                            <div className="w-1.5 h-1.5 rounded-full bg-[#C9A84C] animate-pulse" />
                            <span className="text-xs font-black text-[#0A1628]">
                              {new Date(c.hearings[c.hearings.length-1].date).toLocaleDateString('en-IN', { day: '2-digit', month: 'short' })}
                            </span>
                          </div>
                        ) : null}
                      </div>
                    </td>
                    <td className="px-8 py-6 text-right">
                      <div className="flex justify-end items-center gap-3">
                        {c.status !== CaseStatus.ARCHIVED && (
                          <button 
                            onClick={(e) => { e.stopPropagation(); onArchive(c.id); }}
                            className="p-2.5 text-slate-400 hover:bg-slate-100 hover:text-slate-600 rounded-xl transition-all border border-slate-200"
                            title="Archive Record"
                          >
                            <Archive size={18} />
                          </button>
                        )}
                        <button 
                          onClick={(e) => { e.stopPropagation(); onGenerateNotice(c.id); }}
                          className="p-2.5 text-[#0A1628] hover:bg-[#0A1628] hover:text-[#C9A84C] rounded-xl transition-all border border-slate-200"
                        >
                          <FileText size={18} />
                        </button>
                        <div className="p-2 text-slate-300 group-hover:text-[#C9A84C] transition-colors">
                          <ChevronRight size={20} />
                        </div>
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={6} className="px-8 py-20 text-center">
                    <div className="flex flex-col items-center gap-2 opacity-20">
                      <Layers size={48} />
                      <p className="serif text-xl font-black">NO TRACES FOUND</p>
                      <p className="text-[10px] font-bold uppercase tracking-widest">Adjust filters to broaden observation</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
